class Solution:
    def addMinimum(self, word: str) -> int:
        stack = []
        insertions = 0
        for char in word:
            stack.append(char)
            if char == 'c':
                if len(stack) >= 3 and stack[-3] == 'a' and stack[-2] == 'b':
                    stack = stack[:-3]
                else:
                    insertions += 1 if len(stack) == 1 or stack[-2] != 'b' else 0
                    insertions += 1 if len(stack) <= 2 or stack[-3] != 'a' else 0
                    stack = []
            elif char == 'b':
                if len(stack) >= 2 and stack[-2] == 'a':
                    pass
                else:
                    insertions += 1
                    stack = ['b']
            elif char == 'a':
                if stack and stack[-1] == 'a':
                    insertions += 2
                    stack = ['a']
        insertions += (3 - len(stack)) % 3
        return insertions
